    public boolean heeftMuur(Locatie2D locatie, Direction richting) {

        switch (richting) {
            case Direction.DOWN -> {
                return (controleerMuur(new Locatie2D(locatie.getX()+0, locatie.getY() + 4)) ||
                        controleerMuur(new Locatie2D(locatie.getX()+1, locatie.getY() + 4)) ||
                        controleerMuur(new Locatie2D(locatie.getX()+2, locatie.getY() + 4)) ||
                        controleerMuur(new Locatie2D(locatie.getX()+3, locatie.getY() + 4)));
            }
            case Direction.UP -> {
                return (controleerMuur(new Locatie2D(locatie.getX()+0, locatie.getY() - 1)) ||
                        controleerMuur(new Locatie2D(locatie.getX()+1, locatie.getY() - 1)) ||
                        controleerMuur(new Locatie2D(locatie.getX()+2, locatie.getY() - 1)) ||
                        controleerMuur(new Locatie2D(locatie.getX()+3, locatie.getY() - 1)));
            }
            case Direction.RIGHT -> {
                return (controleerMuur(new Locatie2D(locatie.getX()+4, locatie.getY()+0)) ||
                        controleerMuur(new Locatie2D(locatie.getX()+4, locatie.getY()+1)) ||
                        controleerMuur(new Locatie2D(locatie.getX()+4, locatie.getY()+2)) ||
                        controleerMuur(new Locatie2D(locatie.getX()+4, locatie.getY()+3)));
            }
            case Direction.LEFT -> {
                return (controleerMuur(new Locatie2D(locatie.getX()-1, locatie.getY()+0)) ||
                        controleerMuur(new Locatie2D(locatie.getX()-1, locatie.getY()+1)) ||
                        controleerMuur(new Locatie2D(locatie.getX()-1, locatie.getY()+2)) ||
                        controleerMuur(new Locatie2D(locatie.getX()-1, locatie.getY()+3)));
            }
        }

        return true;
    }

    private boolean controleerMuur(Locatie2D locatie) {
        return map[locatie.getY()][locatie.getX()] != 0;
    }

    private boolean controleerSppokDeur(Locatie2D locatie) {
        return map[locatie.getY()][locatie.getX()] != 4;
    }


    @Override
    public void setupEntities() {
        for (int i = 0; i < 20; i++) {
            addEntity(i, BordTegel.class, new TegelConfig(i));
        }
    }

    @Override
    public int[][] defineMap() {
        return  map;
    }
